from dataclasses import dataclass, field
from decimal import Decimal

@dataclass
class CostCentreAllocation:
    cost_centre: str
    team: str
    allocated_tokens_per_month: int     # Planned allocation
    committed_rate_per_mtok: Decimal

    actual_tokens_ytd: int = 0
    months_elapsed: int = 0

    @property
    def annual_allocation_usd(self) -> Decimal:
        return (
            Decimal(str(self.allocated_tokens_per_month))
            / Decimal("1_000_000")
            * self.committed_rate_per_mtok
            * 12
        )

    def run_rate_annual_usd(self) -> Decimal:
        if self.months_elapsed == 0:
            return Decimal("0")
        monthly_avg = self.actual_tokens_ytd / self.months_elapsed
        return Decimal(str(monthly_avg)) / Decimal("1_000_000") * self.committed_rate_per_mtok * 12

    def variance_pct(self) -> Decimal:
        rr = self.run_rate_annual_usd()
        alloc = self.annual_allocation_usd
        if alloc == 0:
            return Decimal("0")
        return (rr - alloc) / alloc * 100

@dataclass
class EnterpriseCommitTracker:
    vendor: str
    total_annual_commit_usd: Decimal
    allocations: list[CostCentreAllocation] = field(default_factory=list)

    def allocated_total(self) -> Decimal:
        return sum(a.annual_allocation_usd for a in self.allocations)

    def unallocated(self) -> Decimal:
        return self.total_annual_commit_usd - self.allocated_total()

    def run_rate_total(self) -> Decimal:
        return sum(a.run_rate_annual_usd() for a in self.allocations)

    def on_track(self) -> bool:
        return abs(self.run_rate_total() - self.total_annual_commit_usd) / self.total_annual_commit_usd < Decimal("0.10")
